13	// Feature set of sparse decoding kernels
14	enum class DecodeFeatures : int {
15	    HEAD_64,
16	    HEAD_128,
17	
18	    HEAD_DIM_576,
19	    HEAD_DIM_512,
20	
21	    V32_KVCACHE_FORMAT,
22	    MODEL1_KVCACHE_FORMAT,
23	
24	    ATTN_SINK,
25	    TOPK_LENGTH,
26	    EXTRA_KVCACHE,
27	    EXTRA_TOPK_LENGTH
28	};
29	
30	struct DecodeImplMeta {
31	    int num_sm_parts;
32	    int fixed_overhead_num_blocks;
33	    int block_size_topk;
34	};
35	
36	class DecodeImplBase : public ImplBase<
37	    SparseAttnDecodeParams,
38	    DecodeFeatures
39	> {
40	public:
41	    virtual DecodeImplMeta get_meta(int h_q, int s_q) = 0;
42	};
43	
44	class Decode_Sm90_Impl : public DecodeImplBase {
45	    DECLARE_SUPPORTED_FEATURES(
46	        DecodeFeatures::HEAD_64,
47	        DecodeFeatures::HEAD_128,
48	        DecodeFeatures::HEAD_DIM_512,
49	        DecodeFeatures::HEAD_DIM_576,
50	        DecodeFeatures::V32_KVCACHE_FORMAT,
51	        DecodeFeatures::MODEL1_KVCACHE_FORMAT,
52	        DecodeFeatures::ATTN_SINK,
53	        DecodeFeatures::TOPK_LENGTH,
54	        DecodeFeatures::EXTRA_KVCACHE,
55	        DecodeFeatures::EXTRA_TOPK_LENGTH
56	    )
57	
58	public:
59	    DecodeImplMeta get_meta(int h_q, int s_q) override {
60	        Arch arch = Arch();
61	        return {
62	            std::max(arch.num_sms / s_q / (h_q/64), 1),
63	            5,
64	            64
65	        };
66	    }
67	
68	protected:
69	    void run_(const SparseAttnDecodeParams &params, const std::vector<FeatureT> &required_features) override {
70	        DISPATCH_MODEL_TYPE(params.model_type, MODEL_TYPE, [&]() {
71	            DISPATCH_NUM_HEADS(params.h_q, NUM_HEADS, [&]() {
72	                sm90::decode::sparse_fp8::run_flash_splitkv_mla_fp8_sparse_kernel<MODEL_TYPE, NUM_HEADS>(params);
73	            });
74	        });
75	    }
76	};
77	
78	class Decode_Sm100_Head64_Impl : public DecodeImplBase {
79	    DECLARE_SUPPORTED_FEATURES(
80	        DecodeFeatures::HEAD_64,
81	        DecodeFeatures::HEAD_DIM_512,
82	        DecodeFeatures::HEAD_DIM_576,
83	        DecodeFeatures::V32_KVCACHE_FORMAT,
84	        DecodeFeatures::MODEL1_KVCACHE_FORMAT,
85	        DecodeFeatures::ATTN_SINK,
86	        DecodeFeatures::TOPK_LENGTH,
87	        DecodeFeatures::EXTRA_KVCACHE,
88	        DecodeFeatures::EXTRA_TOPK_LENGTH
89	    )
90	
91	public:
92	    DecodeImplMeta get_meta(int h_q, int s_q) override {
93	        Arch arch = Arch();
94	        return {
95	            std::max(arch.num_sms / s_q, 1),
96	            5,
97	            64
98	        };
99	    }
100	
101	protected:
102	    void run_(const SparseAttnDecodeParams &params, const std::vector<FeatureT> &required_features) override {
103	        DISPATCH_MODEL_TYPE(params.model_type, MODEL_TYPE, [&]() {
