110	// An implementation that calls the head64 kernel twice to process head128
111	// Necessary for running V3.2 shape (i.e. h = 128, d_qk = 576) on SM100f
112	class Decode_Sm100_Head64x2_Impl : public DecodeImplBase {
113	    DECLARE_SUPPORTED_FEATURES(
114	        DecodeFeatures::HEAD_128,
115	        DecodeFeatures::HEAD_DIM_512,
116	        DecodeFeatures::HEAD_DIM_576,
117	        DecodeFeatures::V32_KVCACHE_FORMAT,
118	        DecodeFeatures::MODEL1_KVCACHE_FORMAT,
119	        DecodeFeatures::ATTN_SINK,
120	        DecodeFeatures::TOPK_LENGTH,
121	        DecodeFeatures::EXTRA_KVCACHE,
122	        DecodeFeatures::EXTRA_TOPK_LENGTH
123	    )
124	
125	public:
126	    DecodeImplMeta get_meta(int h_q, int s_q) override {
127	        Arch arch = Arch();
128	        return {
129	            std::max(arch.num_sms / s_q, 1),
130	            5,
131	            64
132	        };
133	    }
134	
135	protected:
136	    void run_(const SparseAttnDecodeParams &params, const std::vector<FeatureT> &required_features) override {
137	        DISPATCH_MODEL_TYPE(params.model_type, MODEL_TYPE, [&]() {
138	            for (int start_head_idx = 0; start_head_idx < 128; start_head_idx += 64) {
139	                SparseAttnDecodeParams cur_params = params;
140	                cur_params.q += start_head_idx * params.stride_q_h_q;
141	                if (cur_params.attn_sink) {
142	                    cur_params.attn_sink += start_head_idx;
143	                }
144	                cur_params.lse += start_head_idx;
145	                cur_params.out += start_head_idx * params.stride_o_h_q;
146	                cur_params.lse_accum += start_head_idx;
147	                cur_params.o_accum += start_head_idx * params.stride_o_accum_h_q;
148	                cur_params.h_q = 64;
149	                sm100::decode::head64::run_flash_splitkv_mla_fp8_sparse_kernel<MODEL_TYPE>(cur_params);
150	            }
151	        });
152	    }
153	};
